#include <stdio.h>
#define M 998244353
int main() {
    int N;
    scanf("%d", &N);
    int A[N], C[N], B[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%d", &C[i]);
    }
    for (int i = 0; i < N; i++) {
        long long numerator = C[i];
        long long denominator = 1;
        for (int j = 0; j < N; j++) {
            if (i != j) {
                numerator = (numerator * (A[i] - A[j])) % M;
                denominator = (denominator * (A[i] - A[j])) % M;
            }
        }
        B[i] = (numerator * pow(denominator, M - 2, M)) % M;
    }
    for (int i = 0; i < N; i++) {
        printf("%d ", B[i]);
    }
    return 0;
}

