import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] A = new int[N];
        int[] C = new int[N];
        int[] B = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = scanner.nextInt();
        }
        for (int i = 0; i < N; i++) {
            C[i] = scanner.nextInt();
        }
        final int M = 998244353;
        for (int i = 0; i < N; i++) {
            long numerator = C[i];
            long denominator = 1;
            for (int j = 0; j < N; j++) {
                if (i != j) {
                    numerator = (numerator * (A[i] - A[j])) % M;
                    denominator = (denominator * (A[i] - A[j])) % M;
                }
            }
            B[i] = (int) ((numerator * pow(denominator, M - 2, M)) % M);
        }
        for (int i = 0; i < N; i++) {
            System.out.print(B[i] + " ");
        }
    }
    public static long pow(long a, long b, long mod) {
        long res = 1;
        while (b > 0) {
            if ((b & 1) == 1) {
                res = (res * a) % mod;
            }
            a = (a * a) % mod;
            b >>= 1;
        }
        return res;
    }
}

